type MedicalDisclaimerVariant = "standard" | "bac" | "pregnancy" | "gfr" | "eating-disorder";

const standardText =
  "This calculator provides estimates for informational and educational purposes only. Results are not medical advice and should not replace consultation with a qualified healthcare professional. Always consult your doctor before making health or medical decisions based on any calculation.";

const extraText: Record<Exclude<MedicalDisclaimerVariant, "standard">, string> = {
  bac: "Never use this calculator to determine if you are safe to drive. Blood alcohol content varies significantly between individuals. The only safe choice is not to drive after drinking any alcohol.",
  pregnancy:
    "Pregnancy dates and cycles vary significantly between individuals. Always confirm dates and monitor your pregnancy with your licensed obstetrician or midwife.",
  gfr: "eGFR is a screening estimate only and requires laboratory confirmation and clinical interpretation by a licensed nephrologist or physician. Do not make any treatment decisions based solely on this calculator.",
  "eating-disorder":
    "If you or someone you know is struggling with an eating disorder please contact the National Alliance for Eating Disorders helpline at 1-866-662-1235 or visit allianceforeatingdisorders.com. BMI is a limited screening tool and not a diagnosis.",
};

const variantClass: Record<MedicalDisclaimerVariant, string> = {
  standard:
    "border-amber-200 bg-amber-50 text-amber-950 dark:border-amber-800 dark:bg-amber-950/30 dark:text-amber-100",
  bac: "border-orange-300 bg-orange-50 text-orange-950 dark:border-orange-800 dark:bg-orange-950/35 dark:text-orange-100",
  pregnancy:
    "border-rose-200 bg-rose-50 text-rose-950 dark:border-rose-800 dark:bg-rose-950/30 dark:text-rose-100",
  gfr: "border-sky-200 bg-sky-50 text-sky-950 dark:border-sky-800 dark:bg-sky-950/30 dark:text-sky-100",
  "eating-disorder":
    "border-rose-300 bg-rose-50 text-rose-950 dark:border-rose-800 dark:bg-rose-950/35 dark:text-rose-100",
};

export default function MedicalDisclaimer({ variant = "standard" }: { variant?: MedicalDisclaimerVariant }) {
  const additional = variant === "standard" ? "" : extraText[variant];

  return (
    <div className={`mb-8 rounded-2xl border p-4 text-sm leading-relaxed shadow-sm ${variantClass[variant]}`}>
      <p className="font-extrabold text-current">Medical disclaimer</p>
      <p className="mt-1">{standardText}</p>
      {additional && <p className="mt-2 font-semibold">{additional}</p>}
    </div>
  );
}
